import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TraitType {
  None = "None",
  Desirable = "Desirable",
  Undesirable = "Undesirable"
}

export interface Microbe {
  id: string;
  temperature: number;
  salinity: number;
  nutrients: number;
  trait: TraitType;
}

export interface Range {
  min: number;
  max: number;
}

export interface SiteRequirements {
  temperature: Range;
  salinity: Range;
  nutrients: Range;
}

export interface LevelData {
  levelNumber: number;
  microbes: Microbe[];
  siteRequirements: SiteRequirements;
  requiredSums: {
    temperature: Range;
    salinity: Range;
    nutrients: Range;
  };
}

export interface ValidationResult {
  success: boolean;
  errors: string[];
  stats: {
    avgTemp: number;
    avgSalinity: number;
    avgNutrients: number;
    sumTemp: number;
    sumSalinity: number;
    sumNutrients: number;
    hasDesirable: boolean;
    hasUndesirable: boolean;
  };
}

import { Microbe, SiteRequirements, LevelData, TraitType, ValidationResult, Range } from '../types';

// Constants
const POOL_SIZE = 15;
const TRAIT_PROBS = {
  NONE: 0.6,
  DESIRABLE: 0.25,
  UNDESIRABLE: 0.15
};

const getRandomInt = (min: number, max: number) => 
  Math.floor(Math.random() * (max - min + 1)) + min;

const generateMicrobe = (idNum: number): Microbe => {
  const rand = Math.random();
  let trait = TraitType.None;
  if (rand > TRAIT_PROBS.NONE + TRAIT_PROBS.DESIRABLE) {
    trait = TraitType.Undesirable;
  } else if (rand > TRAIT_PROBS.NONE) {
    trait = TraitType.Desirable;
  }

  return {
    id: `M-${100 + idNum}`,
    temperature: getRandomInt(0, 10),
    salinity: getRandomInt(0, 10),
    nutrients: getRandomInt(0, 10),
    trait
  };
};

const calculateSums = (req: SiteRequirements) => ({
  temperature: { min: req.temperature.min * 3, max: req.temperature.max * 3 },
  salinity: { min: req.salinity.min * 3, max: req.salinity.max * 3 },
  nutrients: { min: req.nutrients.min * 3, max: req.nutrients.max * 3 },
});

// Brute force check if a solution exists for the generated set
const hasValidSolution = (microbes: Microbe[], req: SiteRequirements): boolean => {
  const reqSums = calculateSums(req);

  for (let i = 0; i < microbes.length - 2; i++) {
    for (let j = i + 1; j < microbes.length - 1; j++) {
      for (let k = j + 1; k < microbes.length; k++) {
        const selection = [microbes[i], microbes[j], microbes[k]];

        // Check Traits
        const hasUndesirable = selection.some(m => m.trait === TraitType.Undesirable);
        if (hasUndesirable) continue;

        const hasDesirable = selection.some(m => m.trait === TraitType.Desirable);
        if (!hasDesirable) continue;

        // Check Sums
        const tSum = selection.reduce((acc, m) => acc + m.temperature, 0);
        const sSum = selection.reduce((acc, m) => acc + m.salinity, 0);
        const nSum = selection.reduce((acc, m) => acc + m.nutrients, 0);

        if (tSum < reqSums.temperature.min || tSum > reqSums.temperature.max) continue;
        if (sSum < reqSums.salinity.min || sSum > reqSums.salinity.max) continue;
        if (nSum < reqSums.nutrients.min || nSum > reqSums.nutrients.max) continue;

        return true; // Found at least one valid combination
      }
    }
  }
  return false;
};

export const generateLevel = (levelNumber: number): LevelData => {
  let isValid = false;
  let microbes: Microbe[] = [];
  let requirements: SiteRequirements = {
    temperature: { min: 0, max: 0 },
    salinity: { min: 0, max: 0 },
    nutrients: { min: 0, max: 0 }
  };

  // Keep generating until we find a solvable setup
  while (!isValid) {
    microbes = Array.from({ length: POOL_SIZE }, (_, i) => generateMicrobe(i + 1));

    // Determine difficulty (narrower ranges as levels increase)
    // Level 1: Range 3 (e.g., 3-6)
    // Level 5+: Range 1 or 2
    const spread = Math.max(1, 3 - Math.floor((levelNumber - 1) / 2)); 

    const tBase = getRandomInt(2, 8 - spread);
    const sBase = getRandomInt(2, 8 - spread);
    const nBase = getRandomInt(2, 8 - spread);

    requirements = {
      temperature: { min: tBase, max: tBase + spread },
      salinity: { min: sBase, max: sBase + spread },
      nutrients: { min: nBase, max: nBase + spread }
    };

    if (hasValidSolution(microbes, requirements)) {
      isValid = true;
    }
  }

  return {
    levelNumber,
    microbes,
    siteRequirements: requirements,
    requiredSums: calculateSums(requirements)
  };
};

export const validateSelection = (
  selected: Microbe[], 
  requirements: SiteRequirements
): ValidationResult => {
  const tSum = selected.reduce((acc, m) => acc + m.temperature, 0);
  const sSum = selected.reduce((acc, m) => acc + m.salinity, 0);
  const nSum = selected.reduce((acc, m) => acc + m.nutrients, 0);

  const hasDesirable = selected.some(m => m.trait === TraitType.Desirable);
  const hasUndesirable = selected.some(m => m.trait === TraitType.Undesirable);

  const reqSums = calculateSums(requirements);
  const errors: string[] = [];

  if (hasUndesirable) {
    errors.push("CONTAMINATION ALERT: Selected microbe contains Undesirable Trait.");
  }

  if (!hasDesirable) {
    errors.push("MISSING TRAIT: No microbe with Desirable Trait selected.");
  }

  if (tSum < reqSums.temperature.min || tSum > reqSums.temperature.max) {
    errors.push(`TEMPERATURE IMBALANCE: Sum ${tSum} is outside target ${reqSums.temperature.min}-${reqSums.temperature.max}.`);
  }

  if (sSum < reqSums.salinity.min || sSum > reqSums.salinity.max) {
    errors.push(`SALINITY IMBALANCE: Sum ${sSum} is outside target ${reqSums.salinity.min}-${reqSums.salinity.max}.`);
  }

  if (nSum < reqSums.nutrients.min || nSum > reqSums.nutrients.max) {
    errors.push(`NUTRIENT IMBALANCE: Sum ${nSum} is outside target ${reqSums.nutrients.min}-${reqSums.nutrients.max}.`);
  }

  return {
    success: errors.length === 0,
    errors,
    stats: {
      avgTemp: parseFloat((tSum / 3).toFixed(2)),
      avgSalinity: parseFloat((sSum / 3).toFixed(2)),
      avgNutrients: parseFloat((nSum / 3).toFixed(2)),
      sumTemp: tSum,
      sumSalinity: sSum,
      sumNutrients: nSum,
      hasDesirable,
      hasUndesirable
    }
  };
};

import React from 'react';
import { LevelData } from '../types';
import { Activity, Droplets, Leaf } from 'lucide-react';

interface Props {
  levelData: LevelData;
}

const TargetDisplay: React.FC<Props> = ({ levelData }) => {
  const { siteRequirements: req, requiredSums: sums } = levelData;

  const MetricCard = ({ 
    label, 
    range, 
    sumRange, 
    icon: Icon, 
    color 
  }: { 
    label: string; 
    range: { min: number, max: number }; 
    sumRange: { min: number, max: number }; 
