  }) => (
    <div className={`bg-slate-800 border-l-4 ${color} p-4 rounded-r shadow-md flex-1`}>
      <div className="flex items-center gap-2 mb-2 text-slate-300 uppercase text-xs font-bold tracking-wider">
        <Icon size={16} />
        {label}
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div>
          <div className="text-[10px] text-slate-500 uppercase">Target Avg</div>
          <div className="text-xl font-mono font-bold text-white">
            {range.min}-{range.max}
          </div>
        </div>
        <div>
          <div className="text-[10px] text-slate-500 uppercase">Target Sum</div>
          <div className="text-xl font-mono font-bold text-white">
            {sumRange.min}-{sumRange.max}
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
      <MetricCard 
        label="Temperature" 
        range={req.temperature} 
        sumRange={sums.temperature} 
        icon={Activity}
        color="border-red-500"
      />
      <MetricCard 
        label="Salinity" 
        range={req.salinity} 
        sumRange={sums.salinity} 
        icon={Droplets}
        color="border-blue-500"
      />
      <MetricCard 
        label="Nutrients" 
        range={req.nutrients} 
        sumRange={sums.nutrients} 
        icon={Leaf}
        color="border-green-500"
      />
    </div>
  );
};

export default TargetDisplay;

import React from 'react';
import { Microbe, TraitType } from '../types';
import { ShieldCheck, ShieldAlert, BadgeX } from 'lucide-react';

interface Props {
  microbes: Microbe[];
  selectedIds: string[];
  onToggle: (id: string) => void;
}

const MicrobeTable: React.FC<Props> = ({ microbes, selectedIds, onToggle }) => {
  const getTraitIcon = (trait: TraitType) => {
    switch (trait) {
      case TraitType.Desirable:
        return <div className="flex items-center gap-1 text-emerald-400"><ShieldCheck size={16} /><span className="text-xs uppercase font-bold">Desirable</span></div>;
      case TraitType.Undesirable:
        return <div className="flex items-center gap-1 text-rose-500"><BadgeX size={16} /><span className="text-xs uppercase font-bold">Undesirable</span></div>;
      default:
        return <span className="text-slate-600">-</span>;
    }
  };

  return (
    <div className="overflow-x-auto rounded-lg border border-slate-700 bg-slate-800/50 shadow-inner">
      <table className="w-full text-left text-sm">
        <thead className="bg-slate-900 text-slate-400 uppercase text-xs font-semibold">
          <tr>
            <th className="px-6 py-4">Selection</th>
            <th className="px-6 py-4">ID</th>
            <th className="px-6 py-4">Temp</th>
            <th className="px-6 py-4">Salinity</th>
            <th className="px-6 py-4">Nutrients</th>
            <th className="px-6 py-4">Trait</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-700">
          {microbes.map((microbe) => {
            const isSelected = selectedIds.includes(microbe.id);
            return (
              <tr 
                key={microbe.id}
                onClick={() => onToggle(microbe.id)}
                className={`
                  cursor-pointer transition-colors duration-150
                  ${isSelected ? 'bg-indigo-900/40 hover:bg-indigo-900/50' : 'hover:bg-slate-800'}
                `}
              >
                <td className="px-6 py-3">
                  <div className={`
                    w-5 h-5 rounded border flex items-center justify-center transition-all
                    ${isSelected ? 'bg-indigo-500 border-indigo-400 text-white' : 'border-slate-600 bg-slate-800'}
                  `}>
                    {isSelected && <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>}
                  </div>
                </td>
                <td className="px-6 py-3 font-mono text-slate-200">{microbe.id}</td>
                <td className="px-6 py-3 font-mono text-slate-300">{microbe.temperature}</td>
                <td className="px-6 py-3 font-mono text-slate-300">{microbe.salinity}</td>
                <td className="px-6 py-3 font-mono text-slate-300">{microbe.nutrients}</td>
                <td className="px-6 py-3">
                  {getTraitIcon(microbe.trait)}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

export default MicrobeTable;

import React from 'react';
import { ValidationResult } from '../types';
import { CheckCircle, AlertTriangle, ArrowRight, XCircle } from 'lucide-react';

interface Props {
  result: ValidationResult | null;
  onNext: () => void;
  onRetry: () => void;
}

const FeedbackModal: React.FC<Props> = ({ result, onNext, onRetry }) => {
  if (!result) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className={`
        w-full max-w-2xl rounded-xl border-2 shadow-2xl overflow-hidden
        ${result.success ? 'border-emerald-500 bg-slate-900' : 'border-rose-500 bg-slate-900'}
      `}>
        {/* Header */}
        <div className={`p-6 flex items-center gap-4 ${result.success ? 'bg-emerald-500/10' : 'bg-rose-500/10'}`}>
          {result.success ? (
            <div className="p-3 bg-emerald-500 rounded-full text-white">
              <CheckCircle size={32} />
            </div>
          ) : (
            <div className="p-3 bg-rose-500 rounded-full text-white">
              <XCircle size={32} />
            </div>
          )}
          <div>
            <h2 className="text-2xl font-bold text-white uppercase tracking-wider">
              {result.success ? 'Optimization Successful' : 'Optimization Failed'}
            </h2>
            <p className="text-slate-400 text-sm">
              {result.success ? 'Microbe batch approved for site deployment.' : 'Critical error in selection logic.'}
            </p>
          </div>
        </div>

        {/* Content */}
        <div className="p-6 space-y-6">
          {/* Stats Grid */}
          <div className="grid grid-cols-3 gap-4 text-center">
            <div className="bg-slate-800 p-3 rounded">
              <div className="text-xs text-slate-500 uppercase">Total Temp</div>
              <div className="text-xl font-mono font-bold text-white">{result.stats.sumTemp}</div>
              <div className="text-xs text-slate-400">Avg: {result.stats.avgTemp}</div>
            </div>
            <div className="bg-slate-800 p-3 rounded">
              <div className="text-xs text-slate-500 uppercase">Total Salinity</div>
              <div className="text-xl font-mono font-bold text-white">{result.stats.sumSalinity}</div>
              <div className="text-xs text-slate-400">Avg: {result.stats.avgSalinity}</div>
            </div>
            <div className="bg-slate-800 p-3 rounded">
              <div className="text-xs text-slate-500 uppercase">Total Nutrients</div>
              <div className="text-xl font-mono font-bold text-white">{result.stats.sumNutrients}</div>
              <div className="text-xs text-slate-400">Avg: {result.stats.avgNutrients}</div>
            </div>
          </div>

          {/* Errors List */}
          {!result.success && (
            <div className="bg-rose-950/30 border border-rose-900/50 rounded-lg p-4">
              <h3 className="flex items-center gap-2 text-rose-400 font-bold mb-3 uppercase text-sm">
                <AlertTriangle size={16} />
                Analysis Report
              </h3>
              <ul className="space-y-2">
                {result.errors.map((error, idx) => (
                  <li key={idx} className="flex items-start gap-2 text-rose-200 text-sm font-mono">
                    <span className="mt-1 block w-1.5 h-1.5 rounded-full bg-rose-500 flex-shrink-0" />
                    {error}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-6 bg-slate-800/50 flex justify-end gap-3 border-t border-slate-800">
          {!result.success && (
             <button 
             onClick={onRetry}
             className="px-6 py-2 rounded-lg font-bold text-white bg-slate-700 hover:bg-slate-600 transition-colors"
           >
             Retry Level
           </button>
          )}
          <button 
            onClick={onNext}
            className={`
              px-6 py-2 rounded-lg font-bold text-white flex items-center gap-2 transition-all
              ${result.success 
                ? 'bg-emerald-600 hover:bg-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.3)]' 
                : 'bg-rose-600 hover:bg-rose-500 opacity-50 cursor-not-allowed hidden'}
            `}
            disabled={!result.success}
          >
            {result.success ? 'Proceed to Next Site' : 'Locked'}
            <ArrowRight size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default FeedbackModal;

import React, { useState, useEffect, useCallback } from 'react';
import { generateLevel, validateSelection } from './utils/gameLogic';
import { LevelData, ValidationResult } from './types';
import TargetDisplay from './components/TargetDisplay';
import MicrobeTable from './components/MicrobeTable';
import FeedbackModal from './components/FeedbackModal';
import { Microscope, Play, RefreshCw, Info } from 'lucide-react';

const App: React.FC = () => {
  const [levelNumber, setLevelNumber] = useState(1);
  const [levelData, setLevelData] = useState<LevelData | null>(null);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [validationResult, setValidationResult] = useState<ValidationResult | null>(null);
  const [isIntro, setIsIntro] = useState(true);

  // Load level
  const loadLevel = useCallback((level: number) => {
    const data = generateLevel(level);
    setLevelData(data);
    setSelectedIds([]);
    setValidationResult(null);
  }, []);

  // Initial load
  useEffect(() => {
    loadLevel(1);
  }, [loadLevel]);

  const handleToggleMicrobe = (id: string) => {
    if (validationResult) return; // Freeze selection if showing results

    setSelectedIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(mid => mid !== id);
      } else {
        if (prev.length >= 3) return prev; // Limit to 3
        return [...prev, id];
      }
    });
  };

  const handleSubmit = () => {
    if (!levelData || selectedIds.length !== 3) return;
    const selectedMicrobes = levelData.microbes.filter(m => selectedIds.includes(m.id));
    const result = validateSelection(selectedMicrobes, levelData.siteRequirements);
    setValidationResult(result);
  };

  const handleNextLevel = () => {
    const nextLvl = levelNumber + 1;
    setLevelNumber(nextLvl);
    loadLevel(nextLvl);
  };

  const handleRetry = () => {
    // Generate a NEW level for retry to prevent trial-and-error abuse
    loadLevel(levelNumber);
  };

  if (isIntro) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-900 text-slate-200 p-4">
        <div className="max-w-2xl w-full space-y-8">
          <div className="text-center space-y-4">
            <div className="inline-block p-4 bg-indigo-600 rounded-full shadow-[0_0_30px_rgba(79,70,229,0.3)]">
              <Microscope size={48} className="text-white" />
            </div>
            <h1 className="text-5xl font-bold tracking-tighter text-white">SEA WOLF</h1>
            <p className="text-xl text-slate-400 font-light">Ecosystem Optimization Engine</p>
          </div>

          <div className="bg-slate-800/50 border border-slate-700 rounded-xl p-8 space-y-6">
            <h2 className="text-2xl font-bold text-white border-b border-slate-700 pb-4">Operator Briefing</h2>

            <div className="space-y-4 text-slate-300">
              <div className="flex gap-4">
                <div className="w-8 h-8 rounded bg-indigo-500/20 text-indigo-400 flex items-center justify-center font-bold flex-shrink-0">1</div>
                <div>
                  <h3 className="font-bold text-white">Select 3 Candidates</h3>
                  <p>Choose exactly three microbes from the pool for the target site.</p>
                </div>
              </div>

              <div className="flex gap-4">
                <div className="w-8 h-8 rounded bg-indigo-500/20 text-indigo-400 flex items-center justify-center font-bold flex-shrink-0">2</div>
                <div>
                  <h3 className="font-bold text-white">Match Target Averages</h3>
                  <p>The <span className="text-indigo-400">Sum</span> of their attributes must fall within the target range × 3.</p>
                </div>
              </div>

              <div className="flex gap-4">
                <div className="w-8 h-8 rounded bg-indigo-500/20 text-indigo-400 flex items-center justify-center font-bold flex-shrink-0">3</div>
                <div>
                  <h3 className="font-bold text-white">Verify Traits</h3>
                  <ul className="list-disc pl-4 mt-2 space-y-1 text-sm">
                    <li>Must include at least one <span className="text-emerald-400 font-bold">DESIRABLE</span> trait.</li>
                    <li>Must have ZERO <span className="text-rose-500 font-bold">UNDESIRABLE</span> traits.</li>
                  </ul>
                </div>
              </div>
            </div>

            <button 
              onClick={() => setIsIntro(false)}
              className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-lg text-lg tracking-wide transition-all shadow-lg hover:shadow-indigo-500/25 flex items-center justify-center gap-2"
            >
              <Play size={20} fill="currentColor" />
              INITIATE SIMULATION
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (!levelData) return null;

  return (
    <div className="min-h-screen bg-slate-900 text-slate-200 p-4 md:p-8 font-sans">
      <div className="max-w-6xl mx-auto space-y-6">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 pb-6 border-b border-slate-800">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded shadow-lg">
              <Microscope size={24} className="text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold text-white tracking-tight">SEA WOLF</h1>
              <div className="flex items-center gap-2 text-xs text-indigo-400 font-mono uppercase tracking-wider">
                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                System Online
              </div>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="text-right">
              <div className="text-xs text-slate-500 uppercase font-bold">Current Site</div>
              <div className="text-2xl font-mono text-white">#{levelNumber.toString().padStart(3, '0')}</div>
            </div>
            <div className="h-8 w-px bg-slate-700"></div>
            <button 
              onClick={() => loadLevel(levelNumber)}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded transition-colors"
              title="Reset Level"
            >
              <RefreshCw size={20} />
            </button>
          </div>
        </header>

        <main className="grid lg:grid-cols-4 gap-8">
          {/* Main Workspace */}
          <div className="lg:col-span-3 space-y-6">
            <TargetDisplay levelData={levelData} />

            <div className="bg-slate-800/30 rounded-lg p-1">
               <div className="flex justify-between items-center px-4 py-2">
                  <h3 className="text-sm uppercase font-bold text-slate-400 flex items-center gap-2">
                    <Info size={14}/> 
                    Microbe Pool ({levelData.microbes.length})
                  </h3>
                  <div className="text-sm font-mono text-indigo-400">
                    Selected: {selectedIds.length}/3
                  </div>
               </div>
               <MicrobeTable 
                  microbes={levelData.microbes} 
                  selectedIds={selectedIds} 
                  onToggle={handleToggleMicrobe}
                />
            </div>
          </div>

          {/* Sidebar / Control Panel */}
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-slate-800 rounded-lg p-6 border border-slate-700 shadow-xl sticky top-8">
              <h3 className="text-sm font-bold text-slate-400 uppercase mb-4 tracking-wider">Analysis Console</h3>

              {/* Live Sums - Helper for the user */}
              <div className="space-y-4 mb-8">
                 <div className="space-y-2">
                    <div className="flex justify-between text-sm">
                      <span className="text-slate-500">Temp Sum</span>
                      <span className="font-mono text-white">
                        {selectedIds.reduce((sum, id) => sum + (levelData.microbes.find(m => m.id === id)?.temperature || 0), 0)}
                      </span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-slate-500">Salinity Sum</span>
                      <span className="font-mono text-white">
                        {selectedIds.reduce((sum, id) => sum + (levelData.microbes.find(m => m.id === id)?.salinity || 0), 0)}
                      </span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-slate-500">Nutrient Sum</span>
                      <span className="font-mono text-white">
                         {selectedIds.reduce((sum, id) => sum + (levelData.microbes.find(m => m.id === id)?.nutrients || 0), 0)}
                      </span>
                    </div>
                 </div>
              </div>

              <div className="space-y-3">
                <div className={`
                  p-3 rounded border text-xs text-center
                  ${selectedIds.length === 3 
                    ? 'bg-indigo-900/30 border-indigo-500/50 text-indigo-200' 
                    : 'bg-slate-900 border-slate-700 text-slate-500'}
                `}>
                  {selectedIds.length === 3 
                    ? 'Ready for Validation' 
                    : `Select ${3 - selectedIds.length} more microbe${3 - selectedIds.length === 1 ? '' : 's'}`}
                </div>

                <button
                  onClick={handleSubmit}
                  disabled={selectedIds.length !== 3}
                  className={`
                    w-full py-3 rounded font-bold text-sm uppercase tracking-wider transition-all
                    ${selectedIds.length === 3
                      ? 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg'
                      : 'bg-slate-700 text-slate-400 cursor-not-allowed'}
                  `}
                >
                  Validate Batch
                </button>
              </div>
            </div>

            {/* Legend */}
             <div className="bg-slate-800/50 rounded p-4 text-xs space-y-2 border border-slate-700/50">
                <div className="font-bold text-slate-500 uppercase mb-2">Trait Legend</div>
                <div className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                  <span className="text-slate-300">Desirable (Required)</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-rose-500"></span>
                  <span className="text-slate-300">Undesirable (Banned)</span>
                </div>
             </div>
          </div>
        </main>
      </div>

      <FeedbackModal 
        result={validationResult} 
        onNext={handleNextLevel} 
        onRetry={handleRetry}
      />
    </div>
  );
};

export default App;
